+        fn proptest_blocks_in_group_bounded(group_idx in 0_u32..4) {
+            let geo = make_geometry();
+            let blocks = geo.blocks_in_group(GroupNumber(group_idx));
+            prop_assert!(blocks <= geo.blocks_per_group);
+            prop_assert!(blocks > 0);
