+        ) {
+            let total_blocks = u64::from(bpg) * total_blocks_mult;
+            let group_count = total_blocks.div_ceil(u64::from(bpg));
+            if group_count > u64::from(u32::MAX) { return Ok(()); }
+            #[expect(clippy::cast_possible_truncation)]
