+                inodes_per_group: 256,
+                block_size: 4096,
+                total_blocks,
+                total_inodes: gc * 256,
+                first_data_block: 0,
+                group_count: gc,
+                inode_size: 256,
+            };
+            let sum: u64 = (0..gc).map(|g| u64::from(geo.blocks_in_group(GroupNumber(g)))).sum();
